package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraspaces/internal"
)

func New(args []string) {
	if len(args) < 2 {
		println("Usage: ts new <feature> <branch> [--base <parent>]")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	branch := args[1]
	base := "main"

	// Parse --base flag
	for i := 2; i < len(args); i++ {
		if args[i] == "--base" && i+1 < len(args) {
			base = args[i+1]
			break
		}
	}

	featurePath := internal.FeaturePath(feature)
	path := internal.WorktreePath(feature, branch)

	// Ensure parent directory exists
	internal.Must(os.MkdirAll(featurePath, 0755))

	// Create the worktree at the feature-scoped path
	repoRoot, err := internal.MainRepoRoot()
	if err != nil {
		fmt.Println("Error: must be run from inside a git repository")
		os.Exit(1)
	}

	internal.Must(internal.RunDir(repoRoot, "git", "worktree", "add", path, "-b", branch))

	// Register branch in stack.yaml
	stack, _ := internal.LoadStack(featurePath)
	stack.Branches = append(stack.Branches, internal.StackEntry{Name: branch, Base: base})
	internal.Must(internal.SaveStack(featurePath, stack))

	fmt.Printf("Worktree created: %s (base: %s)\n", path, base)
}

package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraspaces/internal"
)

func StackCmd(args []string) {
	if len(args) < 1 {
		println("Usage: ts stack <feature>")
		return
	}

	feature := args[0]
	featurePath := internal.FeaturePath(feature)

	stack, err := internal.LoadStack(featurePath)
	if err != nil {
		fmt.Println("No stack.yaml found for feature:", feature)
		os.Exit(1)
	}

	if _, err := internal.TopoSort(stack); err != nil {
		fmt.Printf("Warning: %v\n", err)
	}

	internal.PrintTree(stack)
}

package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraspaces/internal"
)

func Sync(args []string) {
	if len(args) < 1 {
		println("Usage: ts sync <feature>")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	featurePath := internal.FeaturePath(feature)

	internal.Must(internal.Run("git", "fetch"))

	stack, err := internal.LoadStack(featurePath)
	if err != nil {
		// No stack.yaml — fall back to rebasing all worktrees against origin/main
		syncFallback(featurePath)
		return
	}

	sorted, err := internal.TopoSort(stack)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	skipped := make(map[string]bool)

	for _, entry := range sorted {
		if skipped[entry.Name] {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "skipped"))
			continue
		}

		path := internal.WorktreePath(feature, entry.Name)
		if _, err := os.Stat(path); os.IsNotExist(err) {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "skipped"))
			continue
		}

		base := entry.Base
		if base == "main" {
			base = "origin/main"
		}

		err := internal.RunDir(path, "git", "rebase", base)
		if err != nil {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "failed"))
			// Skip all descendants
			descs := internal.Descendants(stack, entry.Name)
			for d := range descs {
				skipped[d] = true
			}
			fmt.Printf("    Skipping descendants: %s\n", internal.DescendantsList(stack, entry.Name))
		} else {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "synced"))
		}
	}
}

func syncFallback(featurePath string) {
	entries, _ := os.ReadDir(filepath.Join(featurePath, "worktrees"))
	for _, e := range entries {
		if !e.IsDir() {
			continue
		}
		path := filepath.Join(featurePath, "worktrees", e.Name())
		fmt.Printf("Syncing worktree: %s\n", path)
		internal.Must(internal.RunDir(path, "git", "rebase", "--update-refs", "origin/main"))
	}
}

package internal

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

type StackEntry struct {
	Name string `yaml:"name"`
	Base string `yaml:"base"`
}

type Stack struct {
	Branches []StackEntry `yaml:"branches"`
}

func StackPath(featurePath string) string {
	return filepath.Join(featurePath, "stack.yaml")
}

func LoadStack(featurePath string) (Stack, error) {
	data, err := os.ReadFile(StackPath(featurePath))
	if err != nil {
		return Stack{}, err
	}
	var s Stack
	if err := yaml.Unmarshal(data, &s); err != nil {
		return Stack{}, err
	}
	return s, nil
}

func SaveStack(featurePath string, s Stack) error {
	data, err := yaml.Marshal(&s)
	if err != nil {
		return err
	}
	return os.WriteFile(StackPath(featurePath), data, 0644)
}

// TopoSort returns branches in dependency order (parents before children).
// Returns an error if the graph contains a cycle.
func TopoSort(s Stack) ([]StackEntry, error) {
	// Build adjacency: base → children
	entryMap := make(map[string]StackEntry)
	children := make(map[string][]string)
	inDegree := make(map[string]int)

	for _, e := range s.Branches {
		entryMap[e.Name] = e
		inDegree[e.Name] = 0
	}

	for _, e := range s.Branches {
		// Only count edges where the base is also a tracked branch
		if _, ok := entryMap[e.Base]; ok {
			children[e.Base] = append(children[e.Base], e.Name)
			inDegree[e.Name]++
		}
	}

	// Kahn's algorithm
	var queue []string
	for name, deg := range inDegree {
		if deg == 0 {
			queue = append(queue, name)
		}
	}

	var sorted []StackEntry
	for len(queue) > 0 {
		name := queue[0]
		queue = queue[1:]
		sorted = append(sorted, entryMap[name])
		for _, child := range children[name] {
			inDegree[child]--
			if inDegree[child] == 0 {
				queue = append(queue, child)
			}
		}
	}

	if len(sorted) != len(s.Branches) {
		return nil, fmt.Errorf("cycle detected in stack.yaml")
	}
	return sorted, nil
}

// Descendants returns all transitive children of the given branch.
func Descendants(s Stack, branch string) map[string]bool {
	children := make(map[string][]string)
	for _, e := range s.Branches {
		children[e.Base] = append(children[e.Base], e.Name)
	}

	result := make(map[string]bool)
	queue := []string{branch}
	for len(queue) > 0 {
		name := queue[0]
		queue = queue[1:]
		for _, child := range children[name] {
			if !result[child] {
				result[child] = true
				queue = append(queue, child)
			}
		}
	}
	return result
}

// PrintTree prints the stack as an indented dependency tree.
func PrintTree(s Stack) {
	children := make(map[string][]string)
	roots := make(map[string]bool)

	for _, e := range s.Branches {
		roots[e.Name] = true
	}
	for _, e := range s.Branches {
		children[e.Base] = append(children[e.Base], e.Name)
		// If base is a tracked branch, this entry is not a root
		for _, other := range s.Branches {
			if other.Name == e.Base {
				delete(roots, e.Name)
				break
			}
		}
	}

	var printNode func(name, prefix string, isLast bool)
	printNode = func(name, prefix string, isLast bool) {
		connector := "├── "
		if isLast {
			connector = "└── "
		}
		fmt.Println(prefix + connector + name)

		childPrefix := prefix
		if isLast {
			childPrefix += "    "
		} else {
			childPrefix += "│   "
		}

		kids := children[name]
		for i, child := range kids {
			printNode(child, childPrefix, i == len(kids)-1)
		}
	}

	// Print from each root's base (usually "main")
	bases := make(map[string]bool)
	for _, e := range s.Branches {
		if roots[e.Name] {
			bases[e.Base] = true
		}
	}

	for base := range bases {
		fmt.Printf("(%s)\n", base)
		kids := children[base]
		for i, child := range kids {
			printNode(child, "", i == len(kids)-1)
		}
	}

	if len(s.Branches) == 0 {
		fmt.Println("No branches tracked. Use 'ts new <feature> <branch>' to add branches.")
	}
}

// FormatBranchStatus formats a branch sync result for display.
func FormatBranchStatus(name, status string) string {
	symbols := map[string]string{
		"synced":  "+",
		"failed":  "x",
		"skipped": "-",
	}
	sym := symbols[status]
	if sym == "" {
		sym = "?"
	}
	return fmt.Sprintf("  [%s] %s", sym, name)
}

// DescendantsList returns Descendants as a sorted display string.
func DescendantsList(s Stack, branch string) string {
	descs := Descendants(s, branch)
	var names []string
	for name := range descs {
		names = append(names, name)
	}
	return strings.Join(names, ", ")
}

package internal

import (
	"os"
	"path/filepath"
	"testing"
)

func TestTopoSort_LinearChain(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "auth-routes", Base: "auth-middleware"},
		{Name: "auth-models", Base: "main"},
		{Name: "auth-middleware", Base: "auth-models"},
	}}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// auth-models must come before auth-middleware, which must come before auth-routes
	indexOf := func(name string) int {
		for i, e := range sorted {
			if e.Name == name {
				return i
			}
		}
		return -1
	}

	if indexOf("auth-models") > indexOf("auth-middleware") {
		t.Error("auth-models should come before auth-middleware")
	}
	if indexOf("auth-middleware") > indexOf("auth-routes") {
		t.Error("auth-middleware should come before auth-routes")
	}
}

func TestTopoSort_DAG(t *testing.T) {
	// A→B and A→C (divergent)
	s := Stack{Branches: []StackEntry{
		{Name: "branch-b", Base: "branch-a"},
		{Name: "branch-c", Base: "branch-a"},
		{Name: "branch-a", Base: "main"},
	}}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if len(sorted) != 3 {
		t.Fatalf("expected 3 entries, got %d", len(sorted))
	}

	// branch-a must come before both b and c
	indexOf := func(name string) int {
		for i, e := range sorted {
			if e.Name == name {
				return i
			}
		}
		return -1
	}

	if indexOf("branch-a") > indexOf("branch-b") {
		t.Error("branch-a should come before branch-b")
	}
	if indexOf("branch-a") > indexOf("branch-c") {
		t.Error("branch-a should come before branch-c")
	}
}

func TestTopoSort_CycleDetection(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "a", Base: "b"},
		{Name: "b", Base: "c"},
		{Name: "c", Base: "a"},
	}}

	_, err := TopoSort(s)
	if err == nil {
		t.Fatal("expected cycle error, got nil")
	}
}

func TestTopoSort_SingleBranch(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "feature", Base: "main"},
	}}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(sorted) != 1 || sorted[0].Name != "feature" {
		t.Errorf("expected [feature], got %v", sorted)
	}
}

func TestTopoSort_Empty(t *testing.T) {
	s := Stack{}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(sorted) != 0 {
		t.Errorf("expected empty, got %v", sorted)
	}
}

func TestDescendants(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "a", Base: "main"},
		{Name: "b", Base: "a"},
		{Name: "c", Base: "b"},
		{Name: "d", Base: "a"}, // divergent from b
	}}

	descs := Descendants(s, "a")
	if !descs["b"] || !descs["c"] || !descs["d"] {
		t.Errorf("expected b, c, d as descendants of a, got %v", descs)
	}
	if descs["a"] {
		t.Error("a should not be its own descendant")
	}

	descsB := Descendants(s, "b")
	if !descsB["c"] {
		t.Error("c should be descendant of b")
	}
	if descsB["d"] {
		t.Error("d should not be descendant of b")
	}
}

func TestLoadSaveStack(t *testing.T) {
	tmp := t.TempDir()

	original := Stack{Branches: []StackEntry{
		{Name: "auth-models", Base: "main"},
		{Name: "auth-middleware", Base: "auth-models"},
	}}

	if err := SaveStack(tmp, original); err != nil {
		t.Fatalf("save error: %v", err)
	}

	// Verify file exists
	if _, err := os.Stat(filepath.Join(tmp, "stack.yaml")); err != nil {
		t.Fatalf("stack.yaml not created: %v", err)
	}

	loaded, err := LoadStack(tmp)
	if err != nil {
		t.Fatalf("load error: %v", err)
	}

	if len(loaded.Branches) != 2 {
		t.Fatalf("expected 2 branches, got %d", len(loaded.Branches))
	}
	if loaded.Branches[0].Name != "auth-models" || loaded.Branches[0].Base != "main" {
		t.Errorf("unexpected first entry: %v", loaded.Branches[0])
	}
}

func TestLoadStack_MissingFile(t *testing.T) {
	_, err := LoadStack("/nonexistent/path")
	if err == nil {
		t.Fatal("expected error for missing file")
	}
}
